body.script:
self.__next_f.push([1,"(function () {
 function applyLanguageRules(langCode) {
 if (!langCode) {
 return
 }

 const eyeAbleContainer = document.getElementById('eyeAble_container_ID')
 if (!eyeAbleContainer) {
 return // Assist is not in the DOM (yet)
 }

 const trimmedCode = langCode.trim()

 /* Remove the inline override so normal CSS applies */
 eyeAbleContainer.style.setProperty('display', 'block')

 //change the language in Assist
 if (typeof window.eyeAble_changeLanguage === 'function') {
 window.eyeAble_changeLanguage(trimmedCode)
 }
 }

 function initializeLanguageWatcher() {
 const htmlElement = document.documentElement

 /* Run once immediately */
 applyLanguageRules(htmlElement.getAttribute('lang'))

 /* Watch for subsequent changes */
 const observer = new MutationObserver(function (mutationRecords) {
 mutationRecords.forEach(function (record) {
 if (record.type === 'attributes' && record.attributeName === 'lang') {
 applyLanguageRules(htmlElement.getAttribute('lang'))
 }
 })
 })

 observer.observe(htmlElement, {
 attributes: true,
 attributeFilter: ['lang'],
 })
 }

 function positionUpdate() {
 //check for RTL and set config accordingly
 if(document.documentElement.getAttribute("dir") === "rtl") {
 eyeAble_switchSide('right')
 eyeAble_shadowRoot.querySelector(".iAble_column").style.setProperty("left", "unset")
 eyeAble_shadowRoot.querySelector(".iAble_column").style.setProperty("right", "10px")
 } else {
 eyeAble_switchSide('left')
 eyeAble_shadowRoot.querySelector(".iAble_column").style.setProperty("right", "unset")
 eyeAble_shadowRoot.querySelector(".iAble_column").style.setProperty("left", "10px")
 }
 }
 function positionUpdateOnLanguageChange () {
 const htmlElement = document.documentElement

 /* Watch for subsequent changes */
 const observer = new MutationObserver(function (mutationRecords) {
 mutationRecords.forEach(function (record) {
 if (record.type === 'attributes' && record.attributeName === 'lang') {
 positionUpdate()
 }
 })
 })

 observer.observe(htmlElement, {
 attributes: true,
 attributeFilter: ['lang'],
 })
 }

 /*
 This is needed so that we can place the menu near to the top of the page when the menu is opened.
 When it's closed, the top property is removed so that the menu is aligned in the original place again.
 If the property is not removed when the menu is closed, there will be a hidden element in that place that is clickable which leads to a bad user experience.
 */
 function handleMobileCssOnMenuToggle() {
 const mainContainer = eyeAble_shadowRoot.querySelector('#eyeAble_MainContainerID')

 /* Watch for subsequent changes */
 const observer = new MutationObserver((mutationRecords) => {
 mutationRecords.forEach((record) => {
 if (eyeAble_session_parameters.isMobile) {
 const ariaHidden = record.target.getAttribute('aria-hidden')
 if (ariaHidden === 'false') {
 eyeAble_shadowRoot
 .getElementById('eyeAble_columID')
 .style.setProperty('top', '15%', 'important')
 } else {
 eyeAble_shadowRoot.getElementById('eyeAble_columID').style.removeProperty('top')
 }
 }
 })
 })

 observer.observe(mainContainer, {
 attributeFilter: ['aria-hidden'],
 })
 } 

 if (document.readyState !== 'complete') {
 document.addEventListener("eyeable:init_completed", () => {
 initializeLanguageWatcher()
 positionUpdate()
 positionUpdateOnLanguageChange()
 handleMobileCssOnMenuToggle()
 })
 } else {
 initializeLanguageWatcher()
 positionUpdate()
 handleMobileCssOnMenuToggle()
 }
 })()"])

